# --- Authentication Endpoints (simplified for MVP) ---
@app.route('/register', methods=['POST'])
def register():
    data = request.get_json()
    username = data.get('username')
    email = data.get('email')
    password = data.get('password')

    if not username or not email or not password:
        return jsonify({'message': 'Missing username, email, or password'}), 400

    if User.query.filter_by(username=username).first() or User.query.filter_by(email=email).first():
        return jsonify({'message': 'Username or email already exists'}), 409

    new_user = User(username=username, email=email)
    new_user.set_password(password)
    db.session.add(new_user)
    db.session.commit()
    return jsonify({'message': 'User registered successfully'}), 201

@app.route('/login', methods=['POST'])
def login():
    data = request.get_json()
    username = data.get('username')
    password = data.get('password')

    user = User.query.filter_by(username=username).first()
    if user and user.check_password(password):
        login_user(user)
        return jsonify({'message': 'Logged in successfully', 'user': user.to_dict()}), 200
    return jsonify({'message': 'Invalid username or password'}), 401

@app.route('/logout', methods=['POST'])
@login_required
def logout():
    logout_user()
    return jsonify({'message': 'Logged out successfully'}), 200

@app.route('/me', methods=['GET'])
@login_required
def get_current_user():
    return jsonify({'user': current_user.to_dict()}), 200

# --- Profile Update Endpoint ---
@app.route('/profile', methods=['PUT'])
@login_required
def update_profile():
    data = request.get_json()

    # Define allowed fields for update
    allowed_fields = [
        'email',
        'username',
        'account_type',
        'credits',
        'referral_code',
        'verified_status'
    ]

    updated_fields = {}
    for field in allowed_fields:
        if field in data:
            value = data[field]

            # Basic validation/type checking (can be expanded)
            if field == 'email':
                if not isinstance(value, str) or '@' not in value:
                    return jsonify({'message': 'Invalid email format'}), 400
                if User.query.filter(User.id != current_user.id, User.email == value).first():
                    return jsonify({'message': 'Email already in use by another user'}), 409
            elif field == 'username':
                if not isinstance(value, str) or not value.strip():
                    return jsonify({'message': 'Username cannot be empty'}), 400
                if User.query.filter(User.id != current_user.id, User.username == value).first():
                    return jsonify({'message': 'Username already taken'}), 409
            elif field == 'account_type':
                # For MVP, allow changing account type. In production, this would involve payment.
                if value not in ['free', 'premium', 'enterprise']:
                    return jsonify({'message': 'Invalid account type'}), 400
            elif field == 'credits':
                # For MVP, allow changing credits. In production, this would be managed by internal logic.
                try:
                    value = int(value)
                    if value < 0:
                        return jsonify({'message': 'Credits cannot be negative'}), 400
                except (ValueError, TypeError):
                    return jsonify({'message': 'Credits must be an integer'}), 400
            elif field == 'referral_code':
                # In production, you might have specific rules for referral codes (unique, format, etc.)
                if not isinstance(value, str) and value is not None:
                     return jsonify({'message': 'Referral code must be a string or null'}), 400
                if value and User.query.filter(User.id != current_user.id, User.referral_code == value).first():
                    return jsonify({'message': 'Referral code already in use by another user'}), 409
            elif field == 'verified_status':
                # For MVP, allow changing verified status. In production, this would be system-controlled.
                if not isinstance(value, bool):
                    return jsonify({'message': 'Verified status must be a boolean'}), 400

            # Update the field dynamically
            setattr(current_user, field, value)
            updated_fields[field] = value

    if not updated_fields:
        return jsonify({'message': 'No valid fields provided for update'}), 400

    try:
        db.session.commit()
        return jsonify({'message': 'Profile updated successfully', 'updated_fields': updated_fields, 'user': current_user.to_dict()}), 200
    except Exception as e:
        db.session.rollback()
        print(f"Error updating profile: {e}") # Log the error for debugging
        return jsonify({'message': 'An error occurred during profile update'}), 500

